import{_ as s,C as n,o as r,c as l,j as t,a as i,t as p,E as d}from"./chunks/framework.BzQXgbNp.js";const $=JSON.parse('{"title":"周末游青州","description":"","frontmatter":{},"headers":[],"relativePath":"posts/qingzhou.md","filePath":"posts/qingzhou.md","lastUpdated":1783569911000}'),m={name:"posts/qingzhou.md"},u={style:{color:"var(--vp-c-text-2)","font-size":"14px"}};function f(a,e,c,g,h,_){const o=n("ImageGallery");return r(),l("div",null,[e[0]||(e[0]=t("h1",{id:"周末游青州",tabindex:"-1"},[i("周末游青州 "),t("a",{class:"header-anchor",href:"#周末游青州","aria-label":'Permalink to "周末游青州"'},"​")],-1)),t("p",null,[t("span",u,"📅 发布于："+p(a.$frontmatter.date?new Date(a.$frontmatter.date).toISOString().split("T")[0]:""),1)]),e[1]||(e[1]=t("p",null,"青州为古“九州”之一，名字最初见于《尚书·禹贡》中的“海岱惟青州”，当时青州占据今山东省的大部分区域，现在只是山东省潍坊市下的县级市，从北京到这里只需三小时高铁，很多人仅是为了参观“青州博物馆”而来，它是全国县级市里唯一的国家一级博物馆，这里以震惊中外的龙兴寺石刻造像，海内孤本的明代殿试状元赵秉忠的试卷以及东汉“宜子孙”玉壁为三大镇馆之宝，参观博物馆需要提前三天预约。",-1)),e[2]||(e[2]=t("p",null,"来青州玩用一个周末的时间就可以了，周六白天可以去龙兴寺参观，去驼山看石窟，晚上去逛一下青州古城，古城有很多条街，横竖交错，主街道两边是各种网红食品店，也有像“老槐树煎包”这样名声还不错的小吃店，和“清真隆盛糕点”这样历史悠久的点心店，相对于主街，辅街就显得更接地气一些，街道两侧的巷子里居住着很多当地居民，街道两边商铺售卖的商品和小吃也不仅是面向游客，晚饭可以去古城中的“东哥de鸡”吃炒鸡喝啤酒，味道很棒，周日可以留出四个小时给青州博物馆，用于参观和吃饭，龙兴寺石刻造像位于四层，建议从四层往下逛，到一层后再去餐厅吃饭，味道还不错。",-1)),d(o,{dir:"/images/qingzhou"})])}const q=s(m,[["render",f]]);export{$ as __pageData,q as default};
